import refrom typing import List, Dict, Anyfrom retrieve import build_retrieverDEFAULT_TOP_K = 5MAX_SENTENCES_IN_ANSWER = 3def normalize_text(text: str) -> str:    return re.sub(r"\s+", " ", text).strip()def split_sentences(text: str) -> List[str]:    """    Very simple sentence splitter.    Good enough for this assignment.    """    text = normalize_text(text)    sentences = re.split(r"(?<=[.!?])\s+", text)    return [s.strip() for s in sentences if s.strip()]def extract_query_terms(query: str) -> List[str]:    """    Pull out useful content words from the query.    """    q = query.lower()    important_terms = [        "cost", "price", "fee", "fees", "rebate", "rebates", "medicare",        "prepare", "preparation", "fast", "fasting", "bladder", "drink",        "abdomen", "abdominal", "pelvis", "pelvic", "renal", "kidney",        "pregnancy", "pregnant", "vascular", "breast", "thyroid", "testes",        "risk", "risks", "safe", "harm", "after", "effects",        "results", "report", "doctor",        "long", "duration", "minutes", "take",    ]    found = [term for term in important_terms if term in q]    # Keep a few non-stopword words from the original query too    raw_words = re.findall(r"\b[a-zA-Z]{3,}\b", q)    stopwords = {        "how", "what", "when", "where", "which", "who", "why",        "does", "do", "is", "are", "the", "for", "and", "with",        "from", "that", "this", "will", "would", "into", "your",        "have", "need", "much"    }    for word in raw_words:        if word not in stopwords and word not in found:            found.append(word)    return founddef rerank_results(query: str, results: List[Dict[str, Any]]) -> List[Dict[str, Any]]:    """    Lightweight reranking:    - boost chunks containing specific anatomy / subtype terms from the query    - boost chunks containing multiple query terms    """    query_terms = extract_query_terms(query)    reranked = []    for result in results:        text_lower = result["text"].lower()        bonus = 0.0        # Reward chunks containing important query terms        matched_terms = 0        for term in query_terms:            if term in text_lower:                matched_terms += 1        bonus += 0.02 * matched_terms        # Map common wording variants        if "abdominal" in query.lower() and "abdomen" in text_lower:            bonus += 0.08        if "pelvic" in query.lower() and "pelvis" in text_lower:            bonus += 0.08        if "kidney" in query.lower() and "renal" in text_lower:            bonus += 0.08        reranked.append({            **result,            "rerank_score": result["score"] + bonus        })    reranked.sort(key=lambda x: x["rerank_score"], reverse=True)    return rerankeddef select_relevant_sentences(query: str, results: List[Dict[str, Any]], max_sentences: int = MAX_SENTENCES_IN_ANSWER) -> List[str]:    """    Extract the most relevant sentences from the reranked retrieved chunks.    """    query_terms = extract_query_terms(query)    scored_sentences = []    seen_sentences = set()    for result in results:        for sentence in split_sentences(result["text"]):            sentence_lower = sentence.lower()            # Score sentence by number of matched query terms            term_matches = sum(1 for term in query_terms if term in sentence_lower)            if term_matches == 0:                continue            # Tiny bonuses for especially useful answer-y phrases            bonus = 0            if any(phrase in sentence_lower for phrase in ["you will need to", "fees", "fast", "results", "safe", "risk"]):                bonus += 1            total_score = term_matches + bonus            key = sentence_lower            if key not in seen_sentences:                seen_sentences.add(key)                scored_sentences.append((total_score, sentence))    scored_sentences.sort(key=lambda x: x[0], reverse=True)    selected = [sentence for _, sentence in scored_sentences[:max_sentences]]    return selecteddef is_cost_question(query: str) -> bool:    q = query.lower()    return any(word in q for word in ["cost", "price", "fee", "fees", "rebate", "rebates", "medicare"])def build_grounded_answer(query: str, results: List[Dict[str, Any]]) -> Dict[str, Any]:    """    Produce a grounded answer using only retrieved chunks.    """    if not results:        return {            "answer": (                "I could not find relevant information for that question in the scraped procedure pages."            ),            "sources": [],            "used_chunks": [],            "used_chunk_details": []        }    reranked = rerank_results(query, results)    selected_sentences = select_relevant_sentences(query, reranked)    if not selected_sentences:        return {            "answer": (                "I found related procedure content, but I could not identify a clear grounded answer to that question from the scraped pages."            ),            "sources": sorted({r["url"] for r in reranked}),            "used_chunks": [r["chunk_id"] for r in reranked[:2]],            "used_chunk_details": [                {                    "chunk_id": r["chunk_id"],                    "score": r["score"],                    "rerank_score": round(r["rerank_score"], 4),                    "url": r["url"],                    "text": r["text"],                }                for r in reranked[:2]            ]        }    answer_text = " ".join(selected_sentences)    # Special handling for cost-style questions:    # do not imply a fixed price unless the page gives one.    if is_cost_question(query):        answer_text = (            "I could not find a fixed price in the scraped procedure pages. "            + answer_text        )    return {    "answer": answer_text,    "sources": sorted({r["url"] for r in reranked[:2]}),    "used_chunks": [r["chunk_id"] for r in reranked[:2]],    "used_chunk_details": [        {            "chunk_id": r["chunk_id"],            "score": r["score"],            "rerank_score": round(r["rerank_score"], 4),            "url": r["url"],            "text": r["text"],        }        for r in reranked[:2]    ]}def answer_question(query: str, top_k: int = DEFAULT_TOP_K) -> Dict[str, Any]:    """    End-to-end QA:    retrieve -> rerank -> grounded answer    """    if not query or not query.strip():        raise ValueError("Question must not be empty.")    retriever = build_retriever()    results = retriever.retrieve(query, top_k=top_k)    return build_grounded_answer(query, results)def format_answer_output(response: Dict[str, Any]) -> str:    lines = [        "Answer:",        response["answer"],        "",    ]    if response["sources"]:        lines.append("Sources:")        for source in response["sources"]:            lines.append(f"- {source}")        lines.append("")    if response["used_chunks"]:        lines.append("Used chunks:")        for chunk_id in response["used_chunks"]:            lines.append(f"- {chunk_id}")        lines.append("")    if response.get("used_chunk_details"):        lines.append("Used chunk details:")        for chunk in response["used_chunk_details"]:            lines.append(f"- Chunk ID: {chunk['chunk_id']}")            lines.append(f"  Similarity score: {chunk['score']}")            lines.append(f"  Rerank score: {chunk['rerank_score']}")            lines.append(f"  URL: {chunk['url']}")            lines.append("  Chunk text:")            lines.append(f"  {chunk['text']}")            lines.append("")    return "\n".join(lines).strip()def main() -> None:    print("Grounded Q&A ready. Type a question, or 'exit' to quit.")    while True:        query = input("\nQuestion: ").strip()        if query.lower() in {"exit", "quit"}:            print("Goodbye.")            break        try:            response = answer_question(query)            print()            print(format_answer_output(response))        except ValueError as e:            print(f"Input error: {e}")        except Exception as e:            print(f"Answering error: {e}")if __name__ == "__main__":    main()